import React from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';

const Navbar: React.FC = () => {
    const [isScrolled, setIsScrolled] = React.useState(false);
    const [plannerActive, setPlannerActive] = React.useState(false);
    const location = useLocation();

    React.useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 24);
        };

        handleScroll();
        window.addEventListener('scroll', handleScroll, { passive: true });

        return () => {
            window.removeEventListener('scroll', handleScroll);
        };
    }, []);

    React.useEffect(() => {
        const syncPlannerState = () => {
            const activeOnHome = location.pathname === '/' && document.body.dataset.plannerActive === 'true';
            setPlannerActive(activeOnHome);
        };

        syncPlannerState();
        window.addEventListener('planner-active-change', syncPlannerState as EventListener);

        return () => {
            window.removeEventListener('planner-active-change', syncPlannerState as EventListener);
        };
    }, [location.pathname]);

    const navItems = [
        { name: 'Home', path: '/' },
        { name: 'Map', path: '/map' },
        { name: 'Itinerary', path: '/itinerary' },
        { name: 'Login', path: '/login' },
        { name: 'Profile', path: '/profile' },
    ];

    return (
        <header className={`sticky inset-x-0 top-0 z-50 w-full ${plannerActive ? 'hidden' : ''}`}>
            <motion.nav
                initial={{ y: -20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.45, ease: 'easeOut' }}
                className={`relative w-full border-b border-transparent transition-all duration-300 ${
                    isScrolled ? 'bg-[rgba(2,6,23,0.9)] backdrop-blur-[10px]' : 'bg-[rgba(2,6,23,0.85)] backdrop-blur-[10px]'
                }`}
                aria-label="Primary"
            >
                <span className="pointer-events-none absolute inset-x-0 bottom-0 h-px bg-[linear-gradient(to_right,transparent,rgba(255,255,255,0.08),transparent)]" />
                <div className={`mx-auto flex w-full max-w-[1260px] items-center justify-between px-6 md:px-8 transition-all duration-300 ${isScrolled ? 'h-[3.5rem]' : 'h-[3.8rem]'}`}>
                    <Link
                        to="/"
                        className="group relative flex items-center rounded-md px-1 py-1 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/70"
                    >
                        <img
                            src="/img/transparent-logo.png"
                            alt="CLTOURISM"
                            className="relative h-11 w-auto object-contain md:h-12"
                            loading="eager"
                            decoding="async"
                        />
                    </Link>

                    <div className="hidden items-center gap-2 md:flex" role="list" aria-label="Main navigation links">
                        {navItems.map((item) => {
                            const isActive = item.path === '/'
                                ? location.pathname === '/'
                                : location.pathname.startsWith(item.path);

                            return (
                                <NavLink
                                    key={item.name}
                                    to={item.path}
                                    className={({ isActive: navIsActive }) => {
                                        const activeState = item.path === '/'
                                            ? location.pathname === '/'
                                            : navIsActive || location.pathname.startsWith(item.path);

                                        return `group relative rounded-md px-3 py-2 text-[11px] font-medium uppercase tracking-[0.2em] font-inter transition-colors duration-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/70 ${
                                            activeState ? 'text-bone-white' : 'text-muted hover:text-gold'
                                        }`;
                                    }}
                                >
                                    <span>{item.name}</span>
                                    <span className="pointer-events-none absolute -bottom-0.5 left-2.5 right-2.5 h-px origin-left scale-x-0 bg-gold transition-transform duration-300 group-hover:scale-x-100" />
                                    {isActive && (
                                        <motion.span
                                            layoutId="navbar-active-underline"
                                            className="absolute -bottom-0.5 left-2.5 right-2.5 h-px bg-gold"
                                            transition={{ type: 'spring', stiffness: 380, damping: 32 }}
                                        />
                                    )}
                                </NavLink>
                            );
                        })}
                    </div>
                </div>
            </motion.nav>
        </header>
    );
};

export default Navbar;
